head.script:
scwin.lobranCd     = $c.data.getMemInfo("lobranCd");
scwin.vCurDateF     = WebSquare.date.getCurrentServerDate();
scwin.vCurDate = scwin.vCurDateF.substring(0, 8);


scwin.v_workClsCd = "";
scwin.bOnPopUp = false;

scwin.onpageload = function() {

	scwin.f_SetDefaultData();
	//gr_manCrs.TitleHeight = "30";

    const codeOptions = [

        { grpCd : "OP117", compID : "gr_manCrs:shiftClsCd"}                   
    ];
    $c.data.setCommonCode(codeOptions);
     gr_manCrs.setFixedColumn(3);
};

scwin.onUdcCompleted = function() {

};

scwin.changeVal = function(e){

    var vals = e;
    if(e == "0" || e == ""){
        vals = "";
    } else {
        vals = WebSquare.text.formatFloat(vals, "#,###")
    }
    return vals
};


scwin.sbm_retrieve_submitdone = async function (e) {

    if (e.responseJSON.resultDataSet[0].Code < 0) {
        //$c.gus.cfShowError(sbm_Retrieve);
        return;
    };

    var count = 0;
    for(var i=0; i < ds_man.getRowCount(); i++){
        if(ds_man.getCellData(i, "staffNm") != ""){
            count ++
        }
    }

    if(count > 0 ){

       await scwin.changeZeroData()
        gr_manCrs.mergeCells("byrestriccol");
        gr_manCrs.setFixedColumn(3);
    } else {
        ds_man.removeAll();

        await scwin.changeZeroData()
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003);
    }

};

scwin.changeZeroData = async function(){
    options = {}
        sGroupExpr  = "workDt:weekday:shiftClsCd,staffNm,vsslNm:mgntCommNm:spcRmk:workHh:berthNm:etcfee1:rmk:mgntCommCd:cont";
        await $c.data.applyGridViewGroupExpr(ds_man, gr_manCrs, sGroupExpr, options);

        sGroupExpr2="stdYm,staffNm,cnt1:cnt2:fixCnt:officeCnt:vacaCnt1:vacaCnt2:jclsCont:hclsCont:cont:jclsEtcfee1:hclsEtcfee1:etcfee1"
        await $c.data.applyGridViewGroupExpr(ds_manSum, gr_manSumCrs, sGroupExpr2, options);

        sGroupExpr3="ordCd,staffNm,mgntCd1:mgntCd2:mgntCd3:mgntCd4:mgntCd5:mgntCd6:mgntCd7:mgntCd8:mgntCd9:mgntCd10:mgntCd11:mgntCd12:mgntCd13:mgntCd14:mgntCd15:mgntCd16:mgntCd17:mgntCd18:mgntCd19:mgntCd20:mgntCd21:mgntCd22:mgntCd23:mgntCd24:mgntCd25:mgntCd26:mgntCd27:mgntCd28:mgntCd29:mgntCd30:mgntCd31:mgntCd32:mgntCd33:mgntCd34:mgntCd35:mgntCd36:mgntCd37"
        await $c.data.applyGridViewGroupExpr(ds_manMgntCd, gr_manMgntCdCrs, sGroupExpr3, options);
}

//-------------------------------------------------------------------------
// Default Data Setting
//-------------------------------------------------------------------------
scwin.f_SetDefaultData = async function() {
	ed_wrkDt.setValue(scwin.vCurDate);

    await $c.sbm.execute(sbm_combo);  
    co_ds_combo1.sort('code', 0);

	acb_lobranCd.setValue(scwin.lobranCd);
	lc_occpgrdCd.setValue("01");
	acb_lobranCd.focus();
};

//-------------------------------------------------------------------------
// 본선작업계획현황조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    dma_condition.set("lobranCd", acb_lobranCd.getValue());
    dma_condition.set("occpgrdCd", lc_occpgrdCd.getValue());
    dma_condition.set("wrkDt", ed_wrkDt.getValue());

	// 검색조건 필수 입력 체크


	if (! await $c.gus.cfValidate([acb_lobranCd, ed_wrkDt])) {
		return;
	}

	$c.sbm.execute(sbm_retrieve);   
};

