//-------------------------------------------------------------------------
// 검색영역 Field Clear함.
//-------------------------------------------------------------------------
scwin.f_InitObjects = function() {
	$c.gus.cfInitObjects(tb_mainData);
	scwin.f_SetDefaultData();
};

scwin.f_ExcelDown = async function(){
    let totCnt = ds_man.getRowCount();
    let colCount = gr_manCrs.getTotalCol();
    if (totCnt != 0) {

        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            let sheetTitle = '점소 |'+" " + acb_lobranCd.getText(true) +' / ' + ' 구분 |'+" " + lc_occpgrdCd.getText(true)  +' / ' + ' 작업일자 |'+" " + ed_wrkDt.getDisplayValue();
            const infoArr = [{
                rowIndex: 0, 
                colIndex: 0, 
                rowSpan: 1, 
                colSpan: colCount, 
                text: "근무실적집계", 
                textAlign: "center",
                drawBorder: false, 
                fontSize: "18px"
            },{
                rowIndex : 3, 
                colIndex : 0, 
                rowSpan : 1,
                colSpan : colCount, 
                text : sheetTitle, 
                textAlign : "left",
                fontSize : 12,
                drawBorder:false
            }];



            let options = {};
            options.type           = "1";       
            options.fileName       = "근무실적집계"+".xlsx";
            options.sheetName      = "근무실적집계";
            options.startRowIndex = 4;
            options.startColumnIndex = 0;
            type = 1;
            $c.data.downloadGridViewExcel(gr_manCrs, options, infoArr);
        }
    }else {
        await $c.win.alert(MSG_CM_WRN_002);
    }
};

