            options.startRowIndex = 4;
            options.startColumnIndex = 0;
            options.type = 1;

            $c.data.downloadGridViewExcel(gr_manSumCrs, options, infoArr);
        }
    }else {
        await $c.win.alert(MSG_CM_WRN_002);
    }
};

scwin.f_ExcelDown3 = async function(){
    let totCnt = ds_manMgntCd.getRowCount();
    if (totCnt != 0) {
        let grid;
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {

